// ── Score ring ────────────────────────────────────────────────────────────────

const RADIUS = 42;
const CIRC = 2 * Math.PI * RADIUS;

const scoreConfig = (s) => {
  if (s >= 75)
    return {
      stroke: "#22c55e",
      label: "Strong Match",
      badge: "bg-green-50 text-green-700",
    };
  if (s >= 50)
    return {
      stroke: "#f59e0b",
      label: "Good Match",
      badge: "bg-amber-50 text-amber-700",
    };
  return {
    stroke: "#ef4444",
    label: "Low Match",
    badge: "bg-red-50 text-red-600",
  };
};

const MatchScoreRing = ({ score }) => {
  const { stroke, label, badge } = scoreConfig(score);
  const offset = CIRC - (score / 100) * CIRC;
  return (
    <div className="flex flex-col items-center gap-2">
      <svg
        width="110"
        height="110"
        viewBox="0 0 100 100"
        className="text-gray-900 dark:text-white"
      >
        <circle
          cx="50"
          cy="50"
          r={RADIUS}
          fill="none"
          stroke="#e5e7eb"
          strokeWidth="9"
        />
        <circle
          cx="50"
          cy="50"
          r={RADIUS}
          fill="none"
          stroke={stroke}
          strokeWidth="9"
          strokeLinecap="round"
          strokeDasharray={CIRC}
          strokeDashoffset={offset}
          transform="rotate(-90 50 50)"
          style={{ transition: "stroke-dashoffset 1.2s ease" }}
        />
        <text
          x="50"
          y="47"
          textAnchor="middle"
          dominantBaseline="middle"
          fontSize="22"
          fontWeight="700"
          fill="currentColor"
        >
          {score}
        </text>
        <text
          x="50"
          y="62"
          textAnchor="middle"
          dominantBaseline="middle"
          fontSize="10"
          fill="#9ca3af"
        >
          / 100
        </text>
      </svg>
      <span
        className={`text-xs font-semibold px-2.5 py-1 rounded-full ${badge}`}
      >
        {label}
      </span>
    </div>
  );
};

