              : "bg-blue-500/10 dark:bg-blue-500/20 border border-blue-200 dark:border-blue-500/30"
          }`}
        >
          <p
            className={`text-sm leading-relaxed ${
              isAgent
                ? "text-gray-800 dark:text-gray-200"
                : "text-blue-900 dark:text-blue-100"
