import { createContext, useContext, useState, useEffect } from "react";
import axios from "axios";
import toast from "react-hot-toast";

const AuthContext = createContext(null);

const api = axios.create({
  baseURL: "/api/auth",
  withCredentials: true,
});

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchUser = async () => {
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), 5000);
    try {
      const { data } = await api.get("/me", { signal: controller.signal });
      setUser(data.user);
    } catch {
      setUser(null);
    } finally {
      clearTimeout(timer);
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUser();
  }, []);

  const register = async (username, email, password, turnstileToken) => {
    const { data } = await api.post("/register", {
      username,
      email,
      password,
      turnstileToken,
    });
    toast.success("OTP sent to your email");
    return data;
  };

  const verifyOtp = async (email, otp) => {
    const { data } = await api.post("/verify-otp", { email, otp });
    setUser(data.user);
    toast.success("Email verified!");
    return data;
  };

  const resendOtp = async (email) => {
    const { data } = await api.post("/resend-otp", { email });
    toast.success("OTP resent");
    return data;
  };

  const login = async (email, password, turnstileToken) => {
    const { data } = await api.post("/login", {
      email,
      password,
      turnstileToken,
    });
    setUser(data.user);
    toast.success("Welcome back!");
    return data;
  };

  const googleLogin = async (credential) => {
    const { data } = await api.post("/google", { credential });
    setUser(data.user);
    toast.success("Welcome back!");
    return data;
  };

  const setPassword = async (newPassword) => {
    const { data } = await api.post("/set-password", { newPassword });
    await fetchUser(); // Refresh user to get updated hasPassword flag or authProvider
    toast.success("Password set successfully");
    return data;
  };

  const logout = async () => {
    await api.post("/logout");
    setUser(null);
    toast.success("Logged out");
  };

  const forgotPassword = async (email) => {
    const { data } = await api.post("/forgot-password", { email });
    toast.success("If an account exists, an OTP has been sent");
    return data;
  };

  const resetPassword = async (email, otp, newPassword) => {
    const { data } = await api.post("/reset-password", {
      email,
      otp,
      newPassword,
    });
    toast.success("Password reset successfully");
    return data;
  };

  const updateProfile = async (updates) => {
    const { data } = await api.put("/update-profile", updates);
    setUser(data.user);
    toast.success("Profile updated");
    return data;
  };

  const sendEmailChangeOtp = async (newEmail) => {
    const { data } = await api.post("/send-email-change-otp", { newEmail });
    toast.success("OTP sent to your new email");
    return data;
  };

  const verifyEmailChange = async (newEmail, otp) => {
    const { data } = await api.post("/verify-email-change", { newEmail, otp });
    setUser(data.user);
    toast.success("Email updated successfully");
    return data;
  };

  const sendChangePasswordOtp = async () => {
    const { data } = await api.post("/send-change-password-otp");
    toast.success("OTP sent to your email");
    return data;
  };

  const changePassword = async (otp, newPassword) => {
    const { data } = await api.post("/change-password", { otp, newPassword });
    toast.success("Password changed");
    return data;
  };

  const deleteAccount = async () => {
    await api.delete("/delete-account");
    setUser(null);
    toast.success("Account deleted");
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        setUser,
        loading,
        register,
        verifyOtp,
        resendOtp,
        login,
        googleLogin,
        setPassword,
        logout,
        forgotPassword,
        resetPassword,
        updateProfile,
        sendEmailChangeOtp,
        verifyEmailChange,
        sendChangePasswordOtp,
        changePassword,
        deleteAccount,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used within AuthProvider");
  return ctx;
};

import { createContext, useContext } from "react";
import axios from "axios";
import toast from "react-hot-toast";

const InterviewContext = createContext(null);

const api = axios.create({ baseURL: "/api", withCredentials: true });

export const InterviewProvider = ({ children }) => {
  // ── Analyze / Report ──────────────────────────────────────────────────────

  /**
   * generateReport — sends role + jd + optional resume PDF to Gemini, saves
   * the resulting report, and returns it.
   * @param {{ role?: string, jobDescription: string, selfDescription?: string }} payload
   * @param {File|null} resumeFile — optional PDF
   */
  const generateReport = async (
    payload,
    resumeFile = null,
    signal = undefined,
  ) => {
    const fd = new FormData();
    fd.append("role", payload.role || "");
    fd.append("jobDescription", payload.jobDescription || "");
    fd.append("selfDescription", payload.selfDescription || "");
    if (resumeFile) fd.append("resume", resumeFile);
    const { data } = await api.post("/interview", fd, { signal });
    toast.success("Report generated!");
    return data.report;
  };

  /**
   * getAllReports — returns a summary list of all reports for the current user.
   * @returns {Promise<Array<{_id, title, role, matchScore, createdAt}>>}
   */
  const getAllReports = async () => {
    const { data } = await api.get("/interview/reports");
    return data.reports;
  };

  /**
   * getReportById — returns a single full report.
   * @param {string} reportId
   */
  const getReportById = async (reportId) => {
    const { data } = await api.get(`/interview/report/${reportId}`);
    return data.report;
  };

  /**
   * generatePdf — generates a tailored resume PDF and downloads it directly.
   * @param {string} reportId
   */
  const generatePdf = async (reportId) => {
    const response = await api.post(`/interview/resume/pdf/${reportId}`, null, {
      responseType: "blob",
    });
    const url = URL.createObjectURL(response.data);
    const a = document.createElement("a");
    a.href = url;
    a.download = `resume-${reportId}.pdf`;
    a.click();
    URL.revokeObjectURL(url);
    toast.success("Resume downloaded!");
  };

  // ── Live interview — job mode ─────────────────────────────────────────────

  /**
   * uploadResume — parses a PDF on the server and returns extracted text.
   * @param {File} file
   * @returns {Promise<string>} resumeText
   */
  const uploadResume = async (file) => {
    const fd = new FormData();
    fd.append("resume", file);
    const { data } = await api.post("/interview/upload-resume", fd);
    return data.resumeText;
  };

  /**
   * startInterview — creates a job-mode LiveInterview and returns the first question.
   * @param {{ role: string, jobDescription: string, resumeText?: string }} payload
   * @returns {{ interviewId: string, question: string }}
   */
  const startInterview = async (payload) => {
    const { data } = await api.post("/interview/start", payload);
    return data;
  };

  /**
   * startPrepareInterview — creates a standalone topic-focused prepare session.
   * @param {{ subject: string, topic: string, resumeText?: string }} payload
   * @returns {{ interviewId: string, question: string }}
   */
  const startPrepareInterview = async (payload) => {
    const { data } = await api.post("/interview/prepare/start", payload);
    return data;
  };

  /**
   * answerInterview — submits an answer and returns the AI's next question.
   * @param {string} interviewId
   * @param {string} userAnswer
   * @returns {{ question: string }}
   */
  const answerInterview = async (interviewId, userAnswer) => {
    const { data } = await api.post("/interview/answer", {
      interviewId,
      userAnswer,
    });
    return data;
  };

  /**
   * endInterview — ends the interview and returns structured feedback + score.
   * @param {string} interviewId
   * @param {{ skipFeedback?: boolean }} [options]
   * @returns {{ feedback: object, score: number }}
   */
  const endInterview = async (interviewId, options = {}) => {
    const { data } = await api.post("/interview/end", {
      interviewId,
      ...options,
    });
    return data;
  };

  /**
   * submitInterviewFeedback — saves user star rating/comment after interview end.
   * @param {{ interviewId: string, rating: number, comment?: string }} payload
   */
  const submitInterviewFeedback = async ({ interviewId, rating, comment }) => {
    const { data } = await api.post("/interview/feedback", {
      interviewId,
      rating,
      comment,
    });
    return data;
  };

  /**
   * getAllLiveInterviews — returns a summary list of live interviews for the user.
   * @param {string} [mode] — optional "job" | "prepare" filter
   * @returns {Promise<Array>}
   */
  const getAllLiveInterviews = async (mode) => {
    const url = mode ? `/interview/live?mode=${mode}` : "/interview/live";
    const { data } = await api.get(url);
    return data.interviews;
  };

  /**
   * getLiveInterviewById — returns a single live interview with full conversation + feedback.
   * @param {string} interviewId
   * @returns {Promise<object>}
   */
  const getLiveInterviewById = async (interviewId) => {
    const { data } = await api.get(`/interview/live/${interviewId}`);
    return data.interview;
  };

  /**
   * analyzeQuestion — asks the AI to teach the ideal answer for one question.
   * @param {string} interviewId
   * @param {number} questionIndex — 0-based index in conversation array
   * @returns {Promise<{ source: string, detail: object|null, teaching: { why, structure, sampleAnswer, tip } }>}
   */
  const analyzeQuestion = async (interviewId, questionIndex) => {
    const { data } = await api.post("/interview/analyze-question", {
      interviewId,
      questionIndex,
    });
    return data;
  };

  const deleteLiveInterview = async (id) => {
    await api.delete(`/interview/live/${id}`);
  };

  const deleteReport = async (id) => {
    await api.delete(`/interview/report/${id}`);
  };

  /**
   * fetchJobFromUrl — fetches job details from a LinkedIn job URL.
   * @param {string} url
   * @returns {Promise<{ role: string, company: string, jobDescription: string }>}
   */
  const fetchJobFromUrl = async (url) => {
    const { data } = await api.post(
      "/interview/fetch-job",
      { url },
      { timeout: 15000 },
    );
    return data;
  };

  return (
    <InterviewContext.Provider
      value={{
        generateReport,
        getAllReports,
        getReportById,
        generatePdf,
        uploadResume,
        startInterview,
        startPrepareInterview,
        answerInterview,
        endInterview,
        submitInterviewFeedback,
        getAllLiveInterviews,
        getLiveInterviewById,
        analyzeQuestion,
        deleteLiveInterview,
        deleteReport,
        fetchJobFromUrl,
      }}
    >
      {children}
    </InterviewContext.Provider>
  );
};

export const useInterview = () => {
  const ctx = useContext(InterviewContext);
  if (!ctx)
    throw new Error("useInterview must be used within InterviewProvider");
  return ctx;
};

import { useState, useRef, useCallback, useEffect } from "react";

const DEEPGRAM_AGENT_WS_URL = "wss://agent.deepgram.com/v1/agent/converse";

export function useDeepgramVoiceAgent({
  onTranscript,
  onAgentMessage,
  onError,
}) {
  const [isConnected, setIsConnected] = useState(false);
  const [isAgentSpeaking, setIsAgentSpeaking] = useState(false);
  const [isUserSpeaking, setIsUserSpeaking] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const wsRef = useRef(null);
  const mediaStreamRef = useRef(null);
  const audioContextRef = useRef(null);
  const processorRef = useRef(null);
  const contextRef = useRef(null);
  const keepAliveIntervalRef = useRef(null);
  const isConnectingRef = useRef(false);
  const activeConnectionIdRef = useRef(0);

  const playbackContextRef = useRef(null);
  const nextPlayTimeRef = useRef(0);
  const activeSourcesRef = useRef(0);

  // Queue to hold Agent responses while spacebar is held
  const queuedBlobsRef = useRef([]);
  const queuedTextRef = useRef([]);
  const lastConversationTextRef = useRef({
    user: { text: "", ts: 0 },
    agent: { text: "", ts: 0 },
  });

  const normalizeText = useCallback(
    (value) => (value || "").replace(/\s+/g, " ").trim().toLowerCase(),
    [],
  );

  const isDuplicateConversationText = useCallback(
    (role, content) => {
      const key = role === "user" ? "user" : "agent";
      const normalized = normalizeText(content);
      if (!normalized) return true;

      const now = Date.now();
      const previous = lastConversationTextRef.current[key];
      if (previous.text === normalized && now - previous.ts < 4000) {
        return true;
      }

      lastConversationTextRef.current[key] = { text: normalized, ts: now };
      return false;
    },
    [normalizeText],
  );

  // Play audio chunks from Deepgram
  const playAudioChunk = useCallback(async (blob) => {
    try {
      const arrayBuffer = await blob.arrayBuffer();
      // Raw 16-bit PCM from Deepgram's "linear16" output format
      const view = new Int16Array(arrayBuffer);

      // Initialize a single context for smooth sequential playback
      if (!playbackContextRef.current) {
        playbackContextRef.current = new (
          window.AudioContext || window.webkitAudioContext
        )({
          sampleRate: 48000,
        });
        nextPlayTimeRef.current = playbackContextRef.current.currentTime;
      }
      const audioCtx = playbackContextRef.current;

      // Fill an AudioBuffer (convert Int16 straight to Float32)
      const audioBuffer = audioCtx.createBuffer(1, view.length, 48000);
      const channelData = audioBuffer.getChannelData(0);
      for (let i = 0; i < view.length; i++) {
        channelData[i] = view[i] / 32768;
      }

      // Schedule for continuous playback
      const source = audioCtx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioCtx.destination);

      const playTime = Math.max(audioCtx.currentTime, nextPlayTimeRef.current);

      source.onended = () => {
        activeSourcesRef.current = Math.max(0, activeSourcesRef.current - 1);
        if (activeSourcesRef.current === 0) {
          setIsAgentSpeaking(false);
        }
      };

      activeSourcesRef.current += 1;
      setIsAgentSpeaking(true);

      source.start(playTime);
      nextPlayTimeRef.current = playTime + audioBuffer.duration;
    } catch (err) {
      console.error("[Audio Playback] Error:", err);
    }
  }, []);

  // Handle function calls from Deepgram Agent
  const handleFunctionCall = useCallback(
    async (message) => {
      const { function_call_id, function_name, input } = message;

      if (function_name === "get_ai_response") {
        try {
          // Call our backend to get AI response
          const response = await fetch("/api/interview/voice-agent-response", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            credentials: "include",
            body: JSON.stringify({
              userMessage: input.user_message,
              context: contextRef.current || input.context || {},
            }),
          });

          const data = await response.json();
          const aiResponse =
            data.response ||
            "I didn't understand that. Could you please repeat?";

          // Send function result back to Deepgram
          wsRef.current?.send(
            JSON.stringify({
              type: "FunctionCallResponse",
              function_call_id,
              output: aiResponse,
            }),
          );
        } catch (err) {
          console.error("[Function Call] Error:", err);
          wsRef.current?.send(
            JSON.stringify({
              type: "FunctionCallResponse",
              function_call_id,
              output: "I'm having trouble connecting. Please try again.",
            }),
          );
        }
      }
    },
    [onAgentMessage],
  );

  // Handle messages from Deepgram
  const handleDeepgramMessage = useCallback(
    (message) => {
      switch (message.type) {
        case "UserStartedSpeaking":
          setIsUserSpeaking(true);
          // If the user interrupted the agent, wipe out any queued responses
          queuedBlobsRef.current = [];
          queuedTextRef.current = [];

          if (window.speakMode === "normal") {
            window.speechTurnId = (window.speechTurnId || 0) + 1;
          }
          break;

        case "UserStoppedSpeaking":
          setIsUserSpeaking(false);
          break;

        case "AgentStartedSpeaking":
          if (window.speakMode === "normal" || !window.isSpacePressed) {
            setIsAgentSpeaking(true);
          }
          break;

        case "AgentStoppedSpeaking":
          if (window.speakMode === "normal" || !window.isSpacePressed) {
            setIsAgentSpeaking(false);
          }
          break;

        case "ConversationText":
          // User's transcribed speech
          if (message.role === "user") {
            if (isDuplicateConversationText("user", message.content)) break;
            onTranscript?.(message.content);
          }
          // Agent's text response
          else if (message.role === "agent" || message.role === "assistant") {
            if (isDuplicateConversationText("agent", message.content)) break;
            if (window.speakMode !== "normal" && window.isSpacePressed) {
              queuedTextRef.current.push(message.content);
            } else {
              onAgentMessage?.(message.content);
            }
          }
          break;

        case "AgentAudioDone":
          // Sometimes Deepgram sends the final agent text here
          break;

        case "FunctionCallRequest":
          // Agent wants to call our backend function
          handleFunctionCall(message);
          break;

        case "Welcome":
          console.log(
            "[Deepgram Voice Agent] Session started:",
            message.session_id || message.request_id,
          );
          break;

        case "Error":
          console.error(
            "[Deepgram Voice Agent] Error:",
            message.description || message.message,
          );
          onError?.(message.description || message.message);
          break;

        default:
          // Ignore unhandled message types
          break;
      }
    },
    [
      onTranscript,
      onAgentMessage,
      onError,
      handleFunctionCall,
      isDuplicateConversationText,
    ],
  );

  // Start streaming microphone audio to Deepgram
  const startAudioStreaming = useCallback(
    (stream, ws) => {
      try {
        const audioContext = new (
          window.AudioContext || window.webkitAudioContext
        )({
          sampleRate: 16000,
        });
        audioContextRef.current = audioContext;

        const source = audioContext.createMediaStreamSource(stream);
        const processor = audioContext.createScriptProcessor(4096, 1, 1);
        processorRef.current = processor;

        let isSpeakingState = false;
        let quietFrames = 0;

        processor.onaudioprocess = (e) => {
          if (ws.readyState === WebSocket.OPEN) {
            let inputData = e.inputBuffer.getChannelData(0);

            // Mute the microphone input to Deepgram unless spacebar is pressed OR speakMode is 'normal'
            // We must send silent audio (zeros) instead of nothing to prevent Deepgram from timing out
            if (window.speakMode !== "normal" && !window.isSpacePressed) {
              inputData = new Float32Array(inputData.length);
            }

            // Local user voice activity detection for the visualizer
            let sumSquare = 0;
            for (let i = 0; i < inputData.length; i++) {
              sumSquare += inputData[i] * inputData[i];
            }
            const rms = Math.sqrt(sumSquare / inputData.length);

            if (rms > 0.015) {
              // Threshold for speech
              quietFrames = 0;
              if (!isSpeakingState) {
                isSpeakingState = true;
                setIsUserSpeaking(true);
              }
            } else {
              quietFrames++;
              if (quietFrames > 4 && isSpeakingState) {
                // About 1 second of quiet
                isSpeakingState = false;
                setIsUserSpeaking(false);
              }
            }

            // Mute the agent playback while spacebar is held down (only in 'hold' mode)
            if (
              window.speakMode !== "normal" &&
              window.isSpacePressed &&
              playbackContextRef.current &&
              playbackContextRef.current.state === "running"
            ) {
              playbackContextRef.current.suspend();
            } else if (
              (window.speakMode === "normal" || !window.isSpacePressed) &&
              playbackContextRef.current &&
              playbackContextRef.current.state === "suspended"
            ) {
              playbackContextRef.current.resume();
            }

            // Convert float32 to int16
            const pcm16 = new Int16Array(inputData.length);
            for (let i = 0; i < inputData.length; i++) {
              const s = Math.max(-1, Math.min(1, inputData[i]));
              pcm16[i] = s < 0 ? s * 0x8000 : s * 0x7fff;
            }
            ws.send(pcm16.buffer);
          }
        };

        source.connect(processor);
        processor.connect(audioContext.destination);
      } catch (err) {
        console.error("[Audio Streaming] Error:", err);
        onError?.("Failed to start audio streaming");
      }
    },
    [onError],
  );

  const flushAgentQueues = useCallback(() => {
    // Release all queued text
    while (queuedTextRef.current.length > 0) {
      const text = queuedTextRef.current.shift();
      onAgentMessage?.(text);
    }
    // Release all queued audio
    if (queuedBlobsRef.current.length > 0) {
      setIsAgentSpeaking(true);
    }
    while (queuedBlobsRef.current.length > 0) {
      const blob = queuedBlobsRef.current.shift();
      playAudioChunk(blob);
    }
  }, [onAgentMessage, playAudioChunk]);

  const cleanup = useCallback(() => {
    if (keepAliveIntervalRef.current) {
      clearInterval(keepAliveIntervalRef.current);
    }
    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (audioContextRef.current) {
      if (audioContextRef.current.state !== "closed") {
        audioContextRef.current.close().catch(console.error);
      }
      audioContextRef.current = null;
    }
    if (playbackContextRef.current) {
      if (playbackContextRef.current.state !== "closed") {
        playbackContextRef.current.close().catch(console.error);
      }
      playbackContextRef.current = null;
    }
    nextPlayTimeRef.current = 0;

    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach((track) => track.stop());
      mediaStreamRef.current = null;
    }
    setIsConnected(false);
    setIsAgentSpeaking(false);
    setIsUserSpeaking(false);
  }, []);

  const disconnect = useCallback(() => {
    activeConnectionIdRef.current += 1;
    isConnectingRef.current = false;
    if (wsRef.current) {
      wsRef.current.close();
      wsRef.current = null;
    }
    cleanup();
  }, [cleanup]);

  const connect = useCallback(
    async ({ systemPrompt, context = {} }) => {
      if (isConnectingRef.current) return;
      if (
        wsRef.current &&
        (wsRef.current.readyState === WebSocket.OPEN ||
          wsRef.current.readyState === WebSocket.CONNECTING)
      ) {
        return;
      }

      const apiKey = import.meta.env.VITE_DEEPGRAM_API_KEY;
      if (!apiKey) {
        const errorMsg =
          "Deepgram API key not found. Please add VITE_DEEPGRAM_API_KEY to your .env file.";
        console.error("[Deepgram Voice]", errorMsg);
        onError?.(errorMsg);
        return;
      }

      // Generate a dynamic greeting to start the interview immediately
      let greetingMsg =
        "Hello... and welcome to your session. I am your AI interviewer. Let's take our time... and get to know you. Could you please introduce yourself?";
      if (context?.mode === "job" && context?.role) {
        const companyLabel =
          (context?.companyName || "").toString().trim() ||
          (context?.companyProfile?.name || "").toString().trim();
        const companyContext = companyLabel ? ` at ${companyLabel}` : "";
        greetingMsg = `Hello... and welcome to your job interview for the ${context.role} position${companyContext}. I am your AI interviewer. Let's take our time... and get to know you. Could you please... introduce yourself?`;
      } else if (context?.mode === "prepare" && context?.subject) {
        greetingMsg = `Hello... and welcome to your preparation session covering ${context.subject}. Let's test your skills... and provide interactive feedback. Could you start by telling me... your comfort level with ${context.topic}?`;
      }

      const finalPrompt = systemPrompt
        ? systemPrompt +
          "\n\nCRITICAL INSTRUCTION: You are a professional, soft-spoken, feminine AI interviewer. Speak very gently, calmly, and slowly. ALWAYS use short, concise sentences. Use ellipses (...) and commas frequently to mimic natural, human-like pauses in your speech. Never generate long paragraphs. Keep responses conversational and brief. Wait patiently for the candidate to answer. Ask ONE question at a time. Provide interactive feedback (e.g. 'That is a great point...') to their answers."
        : "You are a professional, calm, soft-spoken, and friendly feminine AI interviewer. Speak very slowly, gently, and clearly. ALWAYS use short, concise sentences. Use ellipses (...) and commas frequently to mimic natural, human-like pauses. Keep responses conversational and brief. Never generate long paragraphs. Ask one question at a time and wait for the candidate to answer before moving on. Provide interactive, conversational feedback to their answers.";

      try {
        isConnectingRef.current = true;
        setIsLoading(true);
        contextRef.current = context;
        const connectionId = activeConnectionIdRef.current + 1;
        activeConnectionIdRef.current = connectionId;

        // Request microphone access
        const stream = await navigator.mediaDevices.getUserMedia({
          audio: true,
        });
        mediaStreamRef.current = stream;

        // Create WebSocket connection for Voice Agent
        const ws = new WebSocket(DEEPGRAM_AGENT_WS_URL, ["token", apiKey]);
        wsRef.current = ws;

        ws.onopen = () => {
          if (connectionId !== activeConnectionIdRef.current) {
            ws.close();
            return;
          }
          console.log("[Deepgram Voice Agent] Connected");

          // Send initial configuration
          ws.send(
            JSON.stringify({
              type: "Settings",
              audio: {
                input: {
                  encoding: "linear16",
                  sample_rate: 16000,
                },
                output: {
                  encoding: "linear16",
                  sample_rate: 48000,
                },
              },
              agent: {
                listen: {
                  provider: {
                    type: "deepgram",
                    model: "nova-2",
                    language: "en-IN",
                  },
                },
                speak: {
                  provider: {
                    type: "deepgram",
                    model: "aura-luna-en",
                  },
                },
                think: {
                  provider: {
                    type: "google",
                    model: "gemini-2.5-flash",
                  },
                  prompt: finalPrompt,
                  functions: [
                    {
                      name: "get_ai_response",
                      description:
                        "Get the next interview question or response from the AI interviewer",
                      parameters: {
                        type: "object",
                        properties: {
                          user_message: {
                            type: "string",
                            description: "The user's answer or message",
                          },
                          context: {
                            type: "object",
                            description:
                              "Interview context (role, job description, etc.)",
                          },
                        },
                        required: ["user_message"],
                      },
                    },
                  ],
                },
                greeting: greetingMsg,
              },
            }),
          );

          setIsConnected(true);
          setIsLoading(false);
          isConnectingRef.current = false;

          // Start pinging KeepAlive every 5 seconds to prevent timeout
          keepAliveIntervalRef.current = setInterval(() => {
            if (ws.readyState === WebSocket.OPEN) {
              ws.send(JSON.stringify({ type: "KeepAlive" }));
            }
          }, 5000);

          startAudioStreaming(stream, ws);
        };

        ws.onmessage = (event) => {
          if (connectionId !== activeConnectionIdRef.current) return;

          if (event.data instanceof Blob) {
            if (window.isSpacePressed) {
              queuedBlobsRef.current.push(event.data);
            } else {
              playAudioChunk(event.data);
            }
            return;
          }

          try {
            const message = JSON.parse(event.data);
            handleDeepgramMessage(message);
          } catch {
            // ignore parsing error for other types
          }
        };

        ws.onerror = (error) => {
          if (connectionId !== activeConnectionIdRef.current) return;
          console.error("[Deepgram Voice Agent] Error:", error);
          onError?.("Voice agent connection error");
          setIsLoading(false);
          isConnectingRef.current = false;
        };

        ws.onclose = () => {
          if (connectionId !== activeConnectionIdRef.current) return;
          console.log("[Deepgram Voice Agent] Disconnected");
          setIsConnected(false);
          setIsLoading(false);
          isConnectingRef.current = false;
          cleanup();
        };
      } catch (err) {
        console.error("[Deepgram Voice Agent] Setup error:", err);
        onError?.(err.message || "Failed to start voice agent");
        setIsLoading(false);
        isConnectingRef.current = false;
      }
    },
    [
      onError,
      handleDeepgramMessage,
      playAudioChunk,
      startAudioStreaming,
      cleanup,
      onAgentMessage,
    ],
  );

  const sendMessage = useCallback((text) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(
        JSON.stringify({
          type: "InjectAgentMessage",
          message: text,
        }),
      );
    }
  }, []);

  useEffect(() => {
    return () => {
      disconnect();
    };
  }, [disconnect]);

  return {
    connect,
    disconnect,
    sendMessage,
    flushAgentQueues,
    isConnected,
    isLoading,
    isAgentSpeaking,
    isUserSpeaking,
  };
}

